import React, { useEffect, useState } from 'react';
import axios from 'axios';

const Tracking = () => {
  const [activeTab, setActiveTab] = useState('On Progress');
  const [trucks, setTrucks] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchData = async (status) => {
    setLoading(true);
    setError('');
    try {
      const response = await axios.get('http://localhost:5000/api/trucks', {
        params: { status }
      });
      setTrucks(response.data);
    } catch (err) {
      setError('Gagal memuat data');
    }
    setLoading(false);
  };

  useEffect(() => {
    // Saat pertama load, ambil data On Progress
    fetchData(activeTab);
  }, [activeTab]);

  const handleTabClick = (tab) => {
    setActiveTab(tab);
  };

  return (
    <div className="container">
      <h1>Truck Tracking</h1>
      
      <div className="tabs">
        <button onClick={() => handleTabClick('On Progress')} className={activeTab === 'On Progress' ? 'active' : ''}>On Progress</button>
        <button onClick={() => handleTabClick('Completed')} className={activeTab === 'Completed' ? 'active' : ''}>Completed</button>
        <button onClick={() => handleTabClick('Trouble')} className={activeTab === 'Trouble' ? 'active' : ''}>Trouble</button>
      </div>

      {loading ? (
        <p>Loading data...</p>
      ) : error ? (
        <p style={{ color: 'red' }}>{error}</p>
      ) : (
        <div className="truck-list">
          {trucks.length === 0 ? (
            <p>Tidak ada data truk untuk status: {activeTab}</p>
          ) : (
            trucks.map((truck) => (
              <div key={truck.truckId} className="truck-card">
                <h3>{truck.truckType} - {truck.truckId}</h3>
                <p>Driver: {truck.driver}</p>
                <p>Status: {truck.status}</p>
                <p>Tanggal: {truck.date}</p>
                {truck.image_url && (
                  <img src={truck.image_url} alt="Truck" width="200" />
                )}
              </div>
            ))
          )}
        </div>
      )}

      <style>{`
        .container { padding: 20px; }
        .tabs { margin-bottom: 20px; }
        button { margin-right: 10px; padding: 8px 15px; }
        .active { background-color: #007bff; color: white; }
        .truck-card { border: 1px solid #ccc; padding: 15px; margin-bottom: 15px; }
      `}</style>
    </div>
  );
};

export default Tracking;
